generated_oml:
// C3: Physical sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor position encoder mounted on the permanent‑magnet synchronous motor of the first axis"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary position encoder located behind the gearbox of the first axis"
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor measuring motor electric current I_M of the first axis"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C5: Data
instance MotorEncoderAngleData : DTDFVocab:Data [
    base:desc "Live motor shaft angle trace (r_M) streamed via MQTT"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBroker, MatlabSimulinkSimulationEngine
]

instance GearboxEncoderAngleData : DTDFVocab:Data [
    base:desc "Live gearbox output angle trace (r_G) streamed via MQTT"
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBroker, MatlabSimulinkSimulationEngine
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Live motor electric current trace (I_M) streamed via MQTT"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTBroker, MatlabSimulinkSimulationEngine
]

// C11: Enablers (tooling and enablers)
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used to stream sensor data (I_M, r_M, r_G, r_out) from the physical axis to the digital shadow"
    DTDFVocab:enables FrictionIdentificationService, ModelUpdatingService, DataVisualizationService
]

instance MatlabSimulinkSimulationEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment executing friction‑less and friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:enables FrictionIdentificationService, ModelUpdatingService
]

instance WebDashboardVisualization : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard visualizing measured versus simulated data"
    DTDFVocab:enables DataVisualizationService
]

instance SysMLModelingTool : DTDFVocab:Enabler [
    base:desc "SysML tool used to create block definition and internal block diagrams of the robot axis"
    DTDFVocab:enables EngineeringModelManagementService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell used to integrate digital shadow models with enterprise asset management"
    DTDFVocab:enables ModelIntegrationService
]

// C6: Services
instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Service that identifies static, kinetic and viscous friction parameters of the gearbox from streamed sensor data"
    DTDFVocab:provides IdentifiedFrictionParametersInsight
]

instance ModelUpdatingService : DTDFVocab:Service [
    base:desc "Service that continuously updates multi‑physics friction models (white‑box and black‑box) using incoming data"
    DTDFVocab:provides ModelUpdateInsight, UpdateMotionControlAction
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Service that visualizes measured sensor traces versus simulated outputs in the integrated web dashboard"
    DTDFVocab:provides MeasuredVsSimulatedInsight
]

instance EngineeringModelManagementService : DTDFVocab:Service [
    base:desc "Service managing SysML engineering models within the digital shadow"
    DTDFVocab:provides EngineeringModelInsight
]

instance ModelIntegrationService : DTDFVocab:Service [
    base:desc "Service that integrates simulation models into the Asset Administration Shell"
    DTDFVocab:provides ModelIntegrationInsight
]

// C17: Insights
instance IdentifiedFrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Identified static, kinetic and viscous friction parameters for the gearbox"
]

instance ModelUpdateInsight : DTDFVocab:Insight [
    base:desc "Updated multi‑physics friction model parameters (white‑box and black‑box) after processing new data"
]

instance MeasuredVsSimulatedInsight : DTDFVocab:Insight [
    base:desc "Comparison results between measured sensor traces and simulated outputs"
]

instance EngineeringModelInsight : DTDFVocab:Insight [
    base:desc "Status and validation of SysML engineering models for the robot axis"
]

instance ModelIntegrationInsight : DTDFVocab:Insight [
    base:desc "Outcome of integrating simulation models into the Asset Administration Shell"
]

// C17: Actions
instance UpdateMotionControlAction : DTDFVocab:Action [
    base:desc "Feedback of identified friction parameters to improve motion control accuracy of the robot axis"
    DTDFVocab:IsAutomatic true
]

// C10: Models/Data (Engineering and Simulation models)
instance SysMLStructureModel : DTDFVocab:Model [
    base:desc "SysML block definition and internal block diagrams describing the first axis of MABI MAX 100 robot"
    DTDFVocab:inputTo SysMLModelingTool
]

instance FrictionlessSimulinkModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink model representing the robot axis without friction"
    DTDFVocab:inputTo MatlabSimulinkSimulationEngine
]

instance CoulombViscousFrictionModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Coulomb‑Viscous friction for the gearbox"
    DTDFVocab:inputTo MatlabSimulinkSimulationEngine
]

instance StribeckFrictionModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Stribeck friction behavior"
    DTDFVocab:inputTo MatlabSimulinkSimulationEngine
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Dahl friction model"
    DTDFVocab:inputTo MatlabSimulinkSimulationEngine
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "Simulink model implementing LuGre friction model"
    DTDFVocab:inputTo MatlabSimulinkSimulationEngine
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The digital shadow consists of a purpose (FrictionDerivation), an asset (the first axis), sources (sensor channels), data traces, processing components (Simulation_M, Simulation_GW, Simulation_GB) that apply simulation models, and a dashboard that aggregates and visualizes the results, forming a coherent DT constellation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability is ensured by linking each data trace to its originating source and processing component; both white‑box analytical and black‑box data‑driven friction models are continuously identified during operation to maintain model fidelity; multi‑physics awareness and comparison of simulated versus measured data serve as validation."
